import java.util.Scanner;

public class SecureBufferConcatenation {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Define maximum allowed length for resulting string
        int maxStringLength = 100; // Set your desired maximum length here

        String fixedString = "Fixed prefix";

        // Check if concatenation will exceed maximum allowed length
        if (fixedString.length() + userInput.length() > maxStringLength) {
            System.out.println("Input exceeds maximum allowed length. Please try again.");
        } else {
            String resultString = fixedString + userInput;
            System.out.println("Resulting string: " + resultString);
        }
    }
}

